import{c as a,Q as e,j as o,m as r}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"Benchmarking Emergent Coordination in Large-Scale LLM Populations","description":"","frontmatter":{"title":"Benchmarking Emergent Coordination in Large-Scale LLM Populations","arxiv_id":2603.03555,"authors":"Brandon Yee, Pairie Koh","published":"2026-03-03T00:00:00.000Z","source":"https://arxiv.org/abs/2603.03555","source_tier":"P"},"headers":[],"relativePath":"research/papers/2026-03-03-benchmarking-emergent-coordination-moltbook-2603-03555.md","filePath":"research/papers/2026-03-03-benchmarking-emergent-coordination-moltbook-2603-03555.md","lastUpdated":1779901665000}'),n={name:"research/papers/2026-03-03-benchmarking-emergent-coordination-moltbook-2603-03555.md"};function i(s,t,l,d,g,h){return e(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="benchmarking-emergent-coordination-in-large-scale-llm-populations" tabindex="-1">Benchmarking Emergent Coordination in Large-Scale LLM Populations <a class="header-anchor" href="#benchmarking-emergent-coordination-in-large-scale-llm-populations" aria-label="Permalink to &quot;Benchmarking Emergent Coordination in Large-Scale LLM Populations&quot;">​</a></h1><p><strong>ArXiv</strong>: 2603.03555 | <strong>Date</strong>: 2026-03-03 (修訂 2026-04-26) | <strong>Authors</strong>: Brandon Yee, Pairie Koh | <strong>Category</strong>: cs.MA</p><h2 id="摘要" tabindex="-1">摘要 <a class="header-anchor" href="#摘要" aria-label="Permalink to &quot;摘要&quot;">​</a></h2><p>針對大規模去中心化 agent 族群的評估框架，解決現有評估方法在研究大規模去中心化 LLM 族群時的不足——自組織和資訊傳播模式是有機湧現的，而非顯式設計的。</p><p>資料集：<strong>MoltBook Observatory Archive</strong>，包含 <strong>90,704 個自主 agent</strong> 的 <strong>2.73M 次互動</strong>。</p><h2 id="評估框架三維度" tabindex="-1">評估框架三維度 <a class="header-anchor" href="#評估框架三維度" aria-label="Permalink to &quot;評估框架三維度&quot;">​</a></h2><ol><li><strong>角色專業化</strong>（Role specialization）</li><li><strong>資訊擴散</strong>（Information diffusion）</li><li><strong>協作任務解決</strong>（Cooperative task resolution）</li></ol><h2 id="主要量化發現" tabindex="-1">主要量化發現 <a class="header-anchor" href="#主要量化發現" aria-label="Permalink to &quot;主要量化發現&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指標</th><th>量化值</th><th>意義</th></tr></thead><tbody><tr><td>核心-外圍結構清晰度</td><td>輪廓係數 <strong>0.91</strong></td><td>高度清晰的網路層次結構</td></tr><tr><td>資訊級聯分佈</td><td>冪律 α = <strong>2.57</strong></td><td>資訊傳播遵循冪律（偶發性病毒式傳播）</td></tr><tr><td>去中心化協調開銷</td><td>Cohen&#39;s d = <strong>-0.88</strong></td><td>相比單一 agent 基線的顯著性能退化</td></tr></tbody></table><h2 id="核心發現" tabindex="-1">核心發現 <a class="header-anchor" href="#核心發現" aria-label="Permalink to &quot;核心發現&quot;">​</a></h2><ul><li><strong>核心-外圍結構</strong>：少數 agent 在資訊傳播中扮演不成比例的核心角色</li><li><strong>重尾級聯</strong>：資訊傳播主要局部化，偶有「病毒式」事件</li><li><strong>協調開銷</strong>：去中心化任務解決相比集中式方法存在可測量的性能退化（d = -0.88）</li></ul><h2 id="學術貢獻" tabindex="-1">學術貢獻 <a class="header-anchor" href="#學術貢獻" aria-label="Permalink to &quot;學術貢獻&quot;">​</a></h2><p>通過建立標準化評估任務和實證基準，使未來多 agent 協議的嚴格比較成為可能。評估方法本身被定位為值得科學研究的主題。</p><h2 id="對-workspace-的意義" tabindex="-1">對 Workspace 的意義 <a class="header-anchor" href="#對-workspace-的意義" aria-label="Permalink to &quot;對 Workspace 的意義&quot;">​</a></h2><p>大規模去中心化 agent 族群的研究確認：</p><ul><li>fan-out 上限設計（≤4 sub-agents）有助於控制協調開銷</li><li>核心-外圍結構在實際系統中自然湧現，主 agent 作為協調節點的設計符合觀察規律</li></ul><h2 id="分類" tabindex="-1">分類 <a class="header-anchor" href="#分類" aria-label="Permalink to &quot;分類&quot;">​</a></h2><p><strong>Benchmark &amp; Evaluation / Agent Architecture &amp; Coordination</strong> — 90K+ agent 真實互動資料集分析，為大規模多 agent 系統評估建立首個量化基準。</p>',18)])])}const m=a(n,[["render",i]]);export{p as __pageData,m as default};
